/**
 * Type declarations for CSS module imports.
 * Allows TypeScript to recognize CSS file imports.
 */
declare module '*.css' {
  const content: Record<string, string>;
  export default content;
}

declare module '*.scss' {
  const content: Record<string, string>;
  export default content;
}

declare module '*.sass' {
  const content: Record<string, string>;
  export default content;
}
